import type { IconEntry, IconProvenance } from "@/lib/registry/types";

/**
 * The shipped icon catalogue as typed entries.
 *
 * - 44 lucide-backed entries name a bundled `lucide-react` icon; this data module imports
 *   nothing from `lucide-react` (the name→component map lives in the renderer), so the
 *   browser STRIDE path no longer transitively pulls in the icon component graph.
 * - 7 third-party brand marks (docker, postgresql, redis, mongodb, nginx, graphql, kafka)
 *   ship as `kind: "paths"` with geometry copied verbatim from the pinned `simple-icons`
 *   16.27.0 package. Each committed source in `tests/fixtures/icons/sources/` is asserted
 *   byte-identical to `node_modules/simple-icons/icons/<slug>.svg` and its trademark owner
 *   and policy URL are recorded from the vendor's authoritative page.
 * - `aws` remains `withdrawn`: its mark (`amazonwebservices`) is absent from the pinned
 *   `simple-icons` release, so its ID stays permanent and resolves to the `archive` fallback
 *   with no artwork shipped. Withdrawal is a data change, never a deletion — no `.thf` file
 *   that references `aws` breaks.
 */

